{"typescriptCode": "
const result = await external_queryTable({
  table: "purchases",
  columns: ["purchased_at", "total", "product_id", "quantity"]
});

const purchases = result.rows as Array<{
  purchased_at: string;
  total: number;
  product_id: number;
  quantity: number;
}>;

// Group by month
const monthlyStats = new Map<string, {
  totalRevenue: number;
  orderCount: number;
  productIds: Set<number>;
}>();

purchases.forEach(purchase => {
  // Extract year-month from the date
  const monthKey = purchase.purchased_at.substring(0, 7); // YYYY-MM format

  if (!monthlyStats.has(monthKey)) {
    monthlyStats.set(monthKey, {
      totalRevenue: 0,
      orderCount: 0,
      productIds: new Set()
    });
  }

  const monthData = monthlyStats.get(monthKey)!;
  monthData.totalRevenue += purchase.total;
  monthData.orderCount += 1;
  monthData.productIds.add(purchase.product_id);
});

// Convert to sorted array and calculate metrics
const monthlyBreakdown = Array.from(monthlyStats.entries())
  .sort((a, b) => a[0].localeCompare(b[0]))
  .map(([month, stats]) => ({
    month,
    totalRevenue: parseFloat(stats.totalRevenue.toFixed(2)),
    orderCount: stats.orderCount,
    averageOrderValue: parseFloat((stats.totalRevenue / stats.orderCount).toFixed(2)),
    distinctProductsSold: stats.productIds.size
  }));

return monthlyBreakdown;
"}
